/**
 * 一键部署 MockUSDC 到 Monad Testnet
 *
 * 用法：
 *   export PAYFI_PRIVATE_KEY="0xd8441f1acb33e10b20069ab558d7bdc04eca1ac3f1c9aafc07445e7172e68500"
 *   npx tsx scripts/deploy-mock-usdc.ts
 *
 * 输出：合约地址 → 复制到 config.ts 的 USDC_ADDRESS
 */

import { createWalletClient, createPublicClient, http } from "viem";
import { privateKeyToAccount } from "viem/accounts";
import { defineChain } from "viem";

// ─── Monad Testnet ──────────────────────────────────────────
const monadTestnet = defineChain({
  id: 10143,
  name: "Monad Testnet",
  nativeCurrency: { name: "MON", symbol: "MON", decimals: 18 },
  rpcUrls: { default: { http: ["https://testnet-rpc.monad.xyz"] } },
  blockExplorers: {
    default: { name: "Monad Explorer", url: "https://testnet.monadexplorer.com" },
  },
  testnet: true,
});

// ─── MockUSDC 字节码（编译好的 creation bytecode）───────────
// 合约源码见 contracts/MockUSDC.sol
// Compiler: 0.8.20, optimization: 200 runs, EVM: paris
// 构造函数参数: _initialSupply = 1000000 (100 万 USDC, 6 decimals)
// abi.encode(uint256(1000000 * 10**6)) = 000000000000000000000000000000000000000000000000000000e8d4a51000

// MockUSDC 字节码（compiled: 0.8.20, optimization 200, EVM paris）
// 构造函数参数见下方 args


// 构造函数参数：1000000 * 10^6 = 1_000_000_000_000
const INITIAL_SUPPLY = 1_000_000n; // 100 万 USDC

// 构造函数 abi.encode(["uint256"], [1_000_000_000_000])
const CONSTRUCTOR_ARGS =
  "000000000000000000000000000000000000000000000000000000e8d4a51000";

const MOCK_USDC_BYTECODE = "" as `0x${string}`;

// ─── 部署函数 ────────────────────────────────────────────────

async function deploy(): Promise<string> {
  const key = process.env.PAYFI_PRIVATE_KEY;
  if (!key || !key.startsWith("0x") || key.length !== 66) {
    throw new Error("❌ 请先设置: export PAYFI_PRIVATE_KEY=\"0x你的测试网私钥\"");
  }

  const account = privateKeyToAccount(key as `0x${string}`);
  const client = createWalletClient({
    account,
    chain: monadTestnet,
    transport: http("https://testnet-rpc.monad.xyz"),
  });
  const publicClient = createPublicClient({
    chain: monadTestnet,
    transport: http("https://testnet-rpc.monad.xyz"),
  });

  console.log("══════════════════════════════════════════════");
  console.log("  🚀 部署 MockUSDC 到 Monad Testnet");
  console.log("══════════════════════════════════════════════");
  console.log();
  console.log(`  部署者: ${account.address}`);
  console.log(`  网络:   Monad Testnet (Chain ID 10143)`);
  console.log(`  初始供应: ${INITIAL_SUPPLY.toLocaleString()} USDC`);
  console.log();

  if (MOCK_USDC_BYTECODE.includes("PASTE")) {
    console.log("══════════════════════════════════════════════");
    console.log("  ⚠️  字节码占位符 — 替代方案");
    console.log("══════════════════════════════════════════════");
    console.log();
    console.log("  Remix Injected Provider 不工作？换个思路:");
    console.log();
    console.log("  1. 在 Remix 选 ENVIRONMENT → JavaScript VM (London)");
    console.log("     这只影响部署，不影响编译。");
    console.log();
    console.log("  2. 编译合约 → Compilation Details → 复制 BYTECODE object");
    console.log();
    console.log("  3. 粘贴到本文件的 MOCK_USDC_BYTECODE");
    console.log();
    console.log("  4. 重新运行: npx tsx scripts/deploy-mock-usdc.ts");
    console.log();
    console.log("  💡 JavaScript VM 不需要 MetaMask，编译功能完全一样");
    console.log("══════════════════════════════════════════════");
    return "";
  }

  console.log("  📡 广播部署交易...");
  const txHash = await client.deployContract({
    abi: [{
      type: "constructor",
      inputs: [{ name: "_initialSupply", type: "uint256" }],
      stateMutability: "nonpayable",
    }],
    bytecode: MOCK_USDC_BYTECODE,
    args: [1_000_000_000_000n], // 100万 * 10^6
  });

  console.log(`  📡 交易哈希: ${txHash}`);
  console.log("  ⏳ 等待确认...");

  const receipt = await publicClient.waitForTransactionReceipt({
    hash: txHash,
    timeout: 120_000,
  });

  const contractAddress = receipt.contractAddress!;
  const explorer = `https://testnet.monadexplorer.com/address/${contractAddress}`;

  console.log();
  console.log("══════════════════════════════════════════════");
  console.log("  ✅ 部署成功！");
  console.log("══════════════════════════════════════════════");
  console.log();
  console.log(`  合约地址: ${contractAddress}`);
  console.log(`  浏览器:   ${explorer}`);
  console.log(`  Gas:      ${receipt.gasUsed}`);
  console.log();
  console.log("  📋 下一步：");
  console.log(`  编辑 src/config.ts:`);
  console.log(`    export const USDC_ADDRESS = "${contractAddress}";`);
  console.log(`    export const USER_ADDRESS = "${account.address}";`);
  console.log();

  return contractAddress;
}

// ─── 执行 ────────────────────────────────────────────────────

deploy()
  .then((addr) => {
    if (addr) {
      console.log(`  export PAYFI_PRIVATE_KEY="..." npx tsx src/agent.ts`);
    }
    process.exit(0);
  })
  .catch((err) => {
    console.error("❌ 部署失败:", (err as Error).message);
    process.exit(1);
  });
